		path.line(to: NSPoint(x: rect.minX + 0.47105 * rect.width, y: rect.minY + 1.00015 * rect.height))
		path.line(to: NSPoint(x: rect.minX + 0.52975 * rect.width, y: rect.minY + 0.94466 * rect.height))
		path.line(to: NSPoint(x: rect.minX + 0.35366 * rect.width, y: rect.minY + 0.77821 * rect.height))
		path.line(to: NSPoint(x: rect.minX + 0.29496 * rect.width, y: rect.minY + 0.83369 * rect.height))
		path.close()
		
		return Path(path.cgPath)
	}
}

